#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int n,q,a[N],p[N],t[4*N];

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=p[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,ans=-2e9;
    if(x<=mid)
        ans=max(ans,query(cur*2,l,mid,x,y));
    if(y>mid)
        ans=max(ans,query(cur*2+1,mid+1,r,x,y));
    return ans;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1,j=1;i<=n;i++){
        while(j<=n && 2*a[i]>a[j])
            j++;
        p[i]=j-i;
    }
    build(1,1,n);
    scanf("%d",&q);
    while(q--){
        int x,y;
        scanf("%d%d",&x,&y);
        int l=0,r=(y-x+1)/2;
        while(l<r){
            int mid=l+r+1>>1;
            if(query(1,1,n,x,x+mid-1)<=y-mid-x+1)
                l=mid;
            else
                r=mid-1;
        }
        printf("%d\n",l);
    }
    return 0;
}
